def validate_xml_structure(xml_string):
    try:
        root = ET.fromstring(xml_string)
        
        response = root.find('.//samlp:Response', SAML_NAMESPACES)
        if response is None:
            response = root if root.tag.endswith('Response') else None
        
        if response is None:
            return False, None
        
        assertion = response.find('.//saml:Assertion', SAML_NAMESPACES)
        if assertion is None:
            return False, None
        
        subject = assertion.find('.//saml:Subject', SAML_NAMESPACES)
        if subject is None:
            return False, None
        
        name_id = subject.find('.//saml:NameID', SAML_NAMESPACES)
        if name_id is None:
            return False, None
        
        return True, root
    except ET.ParseError:
        return False, None


def extract_user_info(saml_response):
    assertion = saml_response.find('.//saml:Assertion', SAML_NAMESPACES)
    if assertion is None:
        return None
    
    subject = assertion.find('.//saml:Subject', SAML_NAMESPACES)
    name_id_element = subject.find('.//saml:NameID', SAML_NAMESPACES)
    name_id = name_id_element.text if name_id_element is not None else None
    
    user_info = {
        'name_id': name_id,
        'attributes': {}
    }
    
    attribute_statement = assertion.find('.//saml:AttributeStatement', SAML_NAMESPACES)
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('.//saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name')
            attr_values = []
            for attr_value in attribute.findall('.//saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    attr_values.append(attr_value.text)
            
            if attr_values:
                user_info['attributes'][attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
    
    return user_info


def validate_saml_conditions(saml_response):
    assertion = saml_response.find('.//saml:Assertion', SAML_NAMESPACES)
    if assertion is None:
        return False
    
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    if conditions is None:
        return True
    
    not_before = conditions.get('NotBefore')
    not_on_or_after = conditions.get('NotOnOrAfter')
    
    current_time = datetime.utcnow()
    time_tolerance = timedelta(minutes=5)
    
    if not_before:
        try:
            not_before_time = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
            not_before_time = not_before_time.replace(tzinfo=None)
            if current_time < (not_before_time - time_tolerance):
                return False
        except (ValueError, AttributeError):
            pass
    
    if not_on_or_after:
        try:
            not_on_or_after_time = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
            not_on_or_after_time = not_on_or_after_time.replace(tzinfo=None)
            if current_time >= (not_on_or_after_time + time_tolerance):
                return False
        except (ValueError, AttributeError):
            pass
    
    audience_restriction = conditions.find('.//saml:AudienceRestriction', SAML_NAMESPACES)
    if audience_restriction is not None:
        audience = audience_restriction.find('.//saml:Audience', SAML_NAMESPACES)
        if audience is not None and audience.text:
            expected_audience = getattr(settings, 'SAML_SP_ENTITY_ID', None)
            if expected_audience and audience.text != expected_audience:
                return False
    
    return True


def get_or_create_user(user_info):
    name_id = user_info.get('name_id')
    if not name_id:
        return None
    
    attributes = user_info.get('attributes', {})
    
    email = attributes.get('email', attributes.get('mail', name_id))
    first_name = attributes.get('firstName', attributes.get('givenName', ''))
    last_name = attributes.get('lastName', attributes.get('surname', ''))
    username = attributes.get('username', name_id.split('@')[0] if '@' in name_id else name_id)
    
    if len(username) > 150:
        username = username[:150]
    
    try:
        user = User.objects.get(username=username)
    except User.DoesNotExist:
        user = User.objects.create_user(
            username=username,
            email=email,
            first_name=first_name[:30] if first_name else '',
            last_name=last_name[:150] if last_name else ''
        )
    
    user.backend = 'django.contrib.auth.backends.ModelBackend'
    
    return user


