    is_valid, saml_root = validate_xml_structure(saml_response_xml)
    if not is_valid:
        return HttpResponseBadRequest('Invalid SAML response structure')
    
    status_code_element = saml_root.find('.//samlp:StatusCode', SAML_NAMESPACES)
    if status_code_element is not None:
        status_value = status_code_element.get('Value', '')
        if 'Success' not in status_value:
            return HttpResponseBadRequest('SAML authentication failed')
    
    if not validate_saml_conditions(saml_root):
        return HttpResponseBadRequest('SAML conditions validation failed')
    
    user_info = extract_user_info(saml_root)
